module RefModule(
    input [3:0] bin_in,
    output [3:0] gray_out
);// Implement the Gray code conversion directly using bitwise operations
    wire __gray_out_tmp = bin_in[3];
    assign gray_out[3] = __gray_out_tmp; // MSB remains the same
